// ─── STORAGE (shared across all devices via window.storage) ───────────────────
// All MKIS data is saved with shared:true, so every device/browser that opens
// this app reads and writes the SAME records instead of separate, per-device
// localStorage copies. This is what makes data appear identically everywhere.
const STORAGE_KEYS = [
  "mkis_students","mkis_termmarks","mkis_monthlymarks","mkis_initials",
  "mkis_bands","mkis_special_bands","mkis_divisions","mkis_school","mkis_accounts","mkis_changerequests",
  "mkis_locked_term","mkis_locked_monthly","mkis_groupwork","mkis_municipalperf","mkis_examtimetable",
];
// One-time migration: if a browser still has old localStorage data and the
// shared store is empty, lift it into shared storage so nothing is lost.
async function migrateLocalStorageOnce() {
  try {
    if (localStorage.getItem("mkis_migrated_v1")) return;
    for (const key of STORAGE_KEYS) {
      const raw = localStorage.getItem(key);
      if (raw == null) continue;
      const existing = await window.storage.get(key, true).catch(() => null);
      if (existing) continue; // shared copy already exists, don't overwrite
      await window.storage.set(key, raw, true);
    }
    localStorage.setItem("mkis_migrated_v1", "1");
  } catch {}
}
async function loadShared(key, def) {
  try {
    const res = await window.storage.get(key, true);
    return res && res.value != null ? JSON.parse(res.value) : def;
  } catch { return def; }
}
// The username of whoever is currently logged in -- set right after login
// and cleared on logout. Every saveShared call stamps this into the
// audit log so the Audit Log page shows the real username.
let _currentAuditUser = "system";
function setAuditUser(username) { _currentAuditUser = username || "system"; }
// Append one audit entry to the shared audit log stored in window.storage.
// detail: a human-readable string describing exactly what changed, e.g.
//   "Term Marks — P4 Term I 2026" or "Student added: John Okello (P3)"
// action: "LOGIN", "LOGOUT", "UPDATE", "ADD", "DELETE", "LOCK", "UNLOCK" etc.
async function writeAuditEntry(key, action, detail) {
  try {
    const res = await window.storage.get("mkis_audit_log", true).catch(()=>null);
    const existing = res?.value ? JSON.parse(res.value) : [];
    const entry = {
      at: new Date().toISOString(),
      who: _currentAuditUser,
      action,
      key,
      detail: detail || "",
    };
    const updated = [entry, ...existing].slice(0, 500);
    await window.storage.set("mkis_audit_log", JSON.stringify(updated), true);
  } catch {}
}
async function saveShared(key, val) {
  try {
    await window.storage.set(key, JSON.stringify(val), true);
  } catch {}
}
