function findAccount(accounts, usernameInput) {
  if (!accounts || !usernameInput) return null;
  return accounts[usernameInput.trim().toLowerCase()] || null;
}
async function verifyAccountLogin(accounts, usernameInput, passwordInput) {
  const acct = findAccount(accounts, usernameInput);
  if (!acct) return null;
  const ok = await verifyPassword(passwordInput, acct.passwordHash);
  return ok ? acct : null;
}
// ─── HELPERS ─────────────────────────────────────────────────────────────────
const toUpper = (s) => (s || "").toUpperCase();
// Resolves which grading scale actually applies to a class: its Special
// Grading Scale override if the school has set one up (and it isn't empty),
// otherwise the normal default bands used everywhere else.
function bandsForClass(cls, bands, specialBands) {
  const special = specialBands?.[cls];
  return (Array.isArray(special) && special.length) ? special : bands;
}
function gradeFor(score, bands) {
  if (score === undefined || score === null || isNaN(score)) return null;
  return bands.find(b => score >= b.min && score <= b.max) || null;
}
function aggOf(score, bands) {
  const g = gradeFor(score, bands);
  if (!g) return 9;
  return parseInt(g.grade.replace(/\D/g,"")) || 9;
}
function gradeLabel(score, bands) {
  const g = gradeFor(score, bands);
  return g ? g.grade : "F9";
}
function divisionOf(totalAgg, numSubjects, divisions) {
  if (!totalAgg || numSubjects === 0) return "U";
  const d = divisions.find(d => totalAgg >= d.min && totalAgg <= d.max);
  return d ? d.name : "U";
}
function remarkFor(score) {
  if (score >= 90) return "Excellent";
  if (score >= 80) return "Very Good";
  if (score >= 75) return "Good";
  if (score >= 65) return "Good";
  if (score >= 55) return "Quite Good";
  if (score >= 45) return "Fair";
  if (score >= 35) return "Pass";
  if (score >= 25) return "Weak";
  return "Fail";
}
// ── Auto-generated Class Teacher's / Head Teacher's comments ──────────────
// Picked automatically from a bank of stock phrases based on the pupil's
// Division (P4-P7) or total marks (P1-P3). Nothing here is stored or
// editable -- it's recomputed fresh every time from the marks already
// entered. A stable per-pupil "seed" (e.g. pupil id + term + year) makes
// the same phrase come up every time for that pupil/period, so it stays
// identical on screen, in the printed copy, in Word, and in the PDF,
// instead of changing on every reload.
function commentHash(seed) {
  const str = String(seed);
  let h = 0;
  for (let i = 0; i < str.length; i++) h = (h * 31 + str.charCodeAt(i)) >>> 0;
  return h;
}
function pickFrom(bank, seed) {
  if (!bank || !bank.length) return "";
  return bank[commentHash(seed) % bank.length];
}
