// ─── PDF EXPORT HELPERS (jsPDF + html2canvas) ──────────────────────────────────
// Rasterizes real on-screen DOM nodes into a paginated A4 PDF, so the PDF
// always matches what the user sees on screen / would get from the print
// button, instead of being rebuilt from scratch with a second layout engine.
const PDF_PAGE_W_MM = 210; // A4 portrait width
const PDF_PAGE_H_MM = 297; // A4 portrait height
// html2canvas only captures the visibly-scrolled portion of elements with
// overflow:auto/scroll (e.g. the horizontally-scrollable Result Sheet table
// on narrow screens). Temporarily expand any such element to its full
// content size before capture, then restore it right after.
function expandOverflowForCapture(root) {
  const candidates = [root, ...root.querySelectorAll("*")];
  const restoreFns = [];
  candidates.forEach(el => {
    const cs = window.getComputedStyle(el);
    const clips = ["auto", "scroll"].includes(cs.overflowX) || ["auto", "scroll"].includes(cs.overflowY);
    if (clips && el.scrollWidth > el.clientWidth + 1) {
      const prev = { overflow: el.style.overflow, overflowX: el.style.overflowX, overflowY: el.style.overflowY, width: el.style.width };
      el.style.overflow = "visible";
      el.style.overflowX = "visible";
      el.style.overflowY = "visible";
      el.style.width = el.scrollWidth + "px";
      restoreFns.push(() => { el.style.overflow = prev.overflow; el.style.overflowX = prev.overflowX; el.style.overflowY = prev.overflowY; el.style.width = prev.width; });
    }
  });
  return () => restoreFns.forEach(fn => fn());
}
// Renders one DOM node to a canvas, then slices that canvas into as many
// A4-width "pages" as its height needs -- so tall tables/lists flow cleanly
// onto additional pages instead of getting cut off. scale=3 (rather than
// the default 1x) oversamples the capture so small table text and digits
// stay sharp once placed into the PDF, instead of looking soft/blurry when
// the page is zoomed in or printed at full size.
async function nodeToPdfPageSlices(node, scale = 3, orientation = "portrait") {
  const pageWmm = orientation === "landscape" ? PDF_PAGE_H_MM : PDF_PAGE_W_MM;
  const pageHmm = orientation === "landscape" ? PDF_PAGE_W_MM : PDF_PAGE_H_MM;
  const restore = expandOverflowForCapture(node);
  // Guard against html2canvas silently producing a corrupted/garbled canvas
  // (random-colored blocks instead of the real content) when the rasterized
  // size would exceed what a browser/GPU can safely allocate for a single
  // canvas -- some devices don't error on overflow, they just hand back
  // garbage pixels. Large, many-column, many-row mark sheets at a fixed
  // scale=3 are exactly the case that can tip over that limit, so we shrink
  // the effective scale just enough to keep the rasterized canvas under a
  // safe ceiling, rather than always using the requested scale blindly.
  const MAX_CANVAS_DIMENSION = 4096;
  const rawW = node.scrollWidth || node.offsetWidth || 1;
  const rawH = node.scrollHeight || node.offsetHeight || 1;
  const effectiveScale = Math.max(1, Math.min(scale, MAX_CANVAS_DIMENSION / rawW, MAX_CANVAS_DIMENSION / rawH));
  let canvas;
  try {
    canvas = await html2canvas(node, {
      scale: effectiveScale, useCORS: true, backgroundColor: "#ffffff",
      // Some captured sections (e.g. Monthly Exams) embed their own on-screen
      // toolbar buttons (Save/Lock, sort toggle) right inside the block being
      // captured. Hide anything marked .no-print in the captured clone only,
      // so the PDF shows just the data, matching what window.print() shows.
      onclone: (doc) => { doc.querySelectorAll(".no-print").forEach(el => { el.style.display = "none"; }); },
    });
  } finally {
    restore();
  }
  const pxPerMm = canvas.width / pageWmm;
  const pageHeightPx = Math.max(1, Math.floor(pxPerMm * pageHmm));
  const slices = [];
  let offset = 0;
  while (offset < canvas.height) {
    const sliceHeightPx = Math.min(pageHeightPx, canvas.height - offset);
    const sliceCanvas = document.createElement("canvas");
    sliceCanvas.width = canvas.width;
    sliceCanvas.height = sliceHeightPx;
    sliceCanvas.getContext("2d").drawImage(canvas, 0, offset, canvas.width, sliceHeightPx, 0, 0, canvas.width, sliceHeightPx);
    // PNG instead of JPEG: this content is almost entirely flat-colour text,
    // lines and table borders rather than photos, so a lossless format keeps
    // edges crisp -- JPEG's compression was the main thing softening/blurring
    // small digits and thin borders in the downloaded PDF before.
    slices.push({ dataUrl: sliceCanvas.toDataURL("image/png"), widthMm: pageWmm, heightMm: sliceHeightPx / pxPerMm });
    offset += sliceHeightPx;
  }
  return slices;
}
// Builds and downloads a single multi-page PDF from an ordered list of DOM
// nodes (e.g. one node per pupil's report card, or [table, analysis] for a
// result sheet, or one node per 3x3 page of Monthly Slips). Each node
// starts on a fresh page; tall nodes span more. orientation applies to
// every page in the PDF (mixed-orientation documents aren't needed here).
async function downloadNodesAsPdf(nodes, filename, orientation = "portrait") {
  const validNodes = nodes.filter(Boolean);
  if (!validNodes.length) return;
  const pdf = new jsPDF({ unit: "mm", format: "a4", orientation, compress: true });
  let started = false;
  for (const node of validNodes) {
    const slices = await nodeToPdfPageSlices(node, 3, orientation);
    for (const slice of slices) {
      if (started) pdf.addPage();
      pdf.addImage(slice.dataUrl, "PNG", 0, 0, slice.widthMm, slice.heightMm);
      started = true;
    }
  }
  pdf.save(filename);
}
// ─── SHARED STYLES ───────────────────────────────────────────────────────────
const lbl = { display:"block", fontSize:11, fontWeight:700, color:"#374151", marginBottom:4, textTransform:"uppercase", letterSpacing:0.5 };
const inp = { padding:"8px 10px", border:"1.5px solid #d1d5db", borderRadius:7, fontSize:13, outline:"none", background:"white", minWidth:80 };
const th  = { padding:"8px 10px", fontWeight:700, textAlign:"center", fontSize:12, whiteSpace:"nowrap", border:"1px solid #d1d5db" };
const td  = { padding:"6px 8px", textAlign:"center", fontSize:12, border:"1px solid #d1d5db" };
const markInput = { width:52, padding:"3px 4px", border:"1px solid #d1d5db", borderRadius:4, fontSize:12, textAlign:"center", background:"white" };
// A mark-entry cell that lets the teacher type freely without interruption.
// Every keystroke only updates local draft text (instant, no save, no
// approval check) so entry feels smooth. The actual save -- and the
// decision on whether a change needs admin approval -- only happens once
// the teacher is done with the cell: on blur (tabbing/clicking away) or
// pressing Enter. That's the moment "existingVal" (the last saved value) is
// compared against the new value, never mid-keystroke.
function MarkInput({ value, existingVal, max, onCommit, style, locked }) {
  const [draft, setDraft] = useState(value ?? "");
  const [pendingFlash, setPendingFlash] = useState(false);
  // Keep the draft in sync whenever the saved value changes from elsewhere
  // (another device, an admin approval landing, switching class/term, etc.)
  // but never while the teacher is actively mid-keystroke in this cell.
  const focusedRef = useRef(false);
  useEffect(() => { if (!focusedRef.current) setDraft(value ?? ""); }, [value]);
  const commit = () => {
    const raw = draft;
    const newVal = raw === "" ? undefined : clampMark(raw, max);
    // Nothing actually changed (e.g. teacher tabbed through without typing) -
    // don't fire a save or a request for a no-op.
    const same = (newVal===undefined && (existingVal===undefined||existingVal===null)) || newVal===existingVal;
    if (!same) {
      const wasFirstEntry = existingVal===undefined || existingVal===null || existingVal==="";
      onCommit(newVal, existingVal);
      if (!wasFirstEntry) { setPendingFlash(true); setTimeout(()=>setPendingFlash(false), 1200); }
    }
  };
  // Once saved & locked, the cell is a genuinely disabled input -- not
  // focusable, not typable, no edit affordance of any kind. The only way
  // back in is the admin's "Unlock" button on the entry screen.
  return (
    <input type="number" min={0} max={max} value={locked ? (value ?? "") : draft} disabled={locked}
      onFocus={()=>{ focusedRef.current = true; }}
      onChange={e=>{
        const raw = e.target.value;
        if (raw === "") { setDraft(""); return; }
        const n = Number(raw);
        // Clamp on every keystroke, not just on blur, so the box can never
        // visually hold (or briefly show) a number outside 0..max.
        if (!isNaN(n)) setDraft(String(Math.max(0, Math.min(max, n))));
      }}
      onBlur={()=>{ focusedRef.current = false; commit(); }}
      onKeyDown={e=>{ if(e.key==="Enter"){ e.target.blur(); } }}
      style={{...style,
        ...(locked ? {background:"#f3f4f6", color:"#6b7280", cursor:"not-allowed"} : {}),
        ...(pendingFlash?{background:"#fef9c3",borderColor:"#f59e0b"}:{})}} />
  );
}
