  // nothing for the layout engine to have to resolve dynamically at print
  // time.
  const headerH = 1.0, nameStripH = 0.5; // cm
  const tableH = 6.3 - headerH - nameStripH; // 4.8cm
  const theadRow1H = 0.55, theadRow2H = 0.45; // cm
